import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void luhnTextbookExample() {
        // Classic Luhn reference: "7992739871" -> 3, full "79927398713" passes
        assertEquals(3, new Solution().luhnCheckDigit("7992739871"));
    }

    @Test
    void trivialZero() {
        // Single digit "0" -> check digit 0, full "00" passes Luhn
        assertEquals(0, new Solution().luhnCheckDigit("0"));
    }

    @Test
    void singleDigitOne() {
        // "1" -> check digit 8, full "18" passes: double(1)=2, add 8 -> 10
        assertEquals(8, new Solution().luhnCheckDigit("1"));
    }

    @Test
    void visaStylePartial() {
        // Partial Visa-style number; check digit must make it pass
        int check = new Solution().luhnCheckDigit("453914880343646");
        assertTrue(check >= 0 && check <= 9);
        // Verify the full number actually passes Luhn
        String full = "453914880343646" + check;
        assertTrue(luhnPasses(full), "Full number should pass Luhn");
    }

    @Test
    void roundTripVerification() {
        // For any partial, appending the check digit must yield a Luhn-valid number
        String partial = "7992739871";
        int check = new Solution().luhnCheckDigit(partial);
        assertTrue(luhnPasses(partial + check));
    }

    @Test
    void allNinesPartial() {
        int check = new Solution().luhnCheckDigit("9999999999");
        assertTrue(luhnPasses("9999999999" + check));
    }

    // Helper: verify a complete number passes Luhn
    private boolean luhnPasses(String number) {
        int sum = 0;
        boolean doubleIt = false;
        for (int i = number.length() - 1; i >= 0; i--) {
            int d = number.charAt(i) - '0';
            if (doubleIt) {
                d *= 2;
                if (d > 9) d -= 9;
            }
            sum += d;
            doubleIt = !doubleIt;
        }
        return sum % 10 == 0;
    }
}
